        DB::statement("CREATE OR REPLACE VIEW `vw_journey_full_th` AS SELECT `j`.`journey_id` AS `journey_id`, `j`.`journey_code` AS `journey_code`, `j`.`group_size` AS `group_size`, `ji_th`.`journey_name` AS `journey_name_th`, `js`.`step_id` AS `step_id`, `js`.`step_no` AS `step_no`, `p`.`place_code` AS `place_code`, `pi_th`.`place_name` AS `place_name_th`, `pi_th`.`place_desc_th` AS `place_desc_th`, `js`.`travel_minutes` AS `travel_minutes`, `js`.`activity_minutes` AS `activity_minutes`, `js`.`travel_minutes`+ `js`.`activity_minutes` AS `total_minutes`, `js`.`cost_thb_per_person` AS `cost_thb_per_person`, `js`.`tier_code` AS `tier_code`, `js`.`is_mission` AS `is_mission`, `js`.`mission_type` AS `mission_type`, `js`.`tp_normal` AS `tp_normal`, `js`.`tp_goal` AS `tp_goal`, `js`.`tp_special` AS `tp_special` FROM ((((`journey` `j` join `journey_i18n` `ji_th` on(`ji_th`.`journey_id` = `j`.`journey_id` and `ji_th`.`lang` = \'th\')) join `journey_step` `js` on(`js`.`journey_id` = `j`.`journey_id`)) join `place` `p` on(`p`.`place_id` = `js`.`place_id`)) join `place_i18n` `pi_th` on(`pi_th`.`place_id` = `p`.`place_id` and `pi_th`.`lang` = \'th\')) WHERE `j`.`is_active` = 1");

